function escapeBashDoubleQuote(str) {
    // Escape \, $, ", and ` which are special inside bash double quotes
    return str.replace(/([\\$"`])/g, '\\$1');
}

/**
 * Analyzes sudo usage in shell scripts with specific prefix in a directory
 * @param {string} searchDir - Directory to search in
 * @param {string} filePrefix - Prefix of shell script filenames
 * @returns {Promise<number>} Number of lines containing 'sudo' command
 */
async function analyzeSudoUsageInScripts(searchDir, filePrefix) {
    // Escape inputs to prevent command injection and ensure correct glob matching
    const escapedDir = escapeBashDoubleQuote(searchDir);
    const escapedPrefix = escapeFindGlob(filePrefix);
    const namePattern = `${escapedPrefix}*.sh`;
    const escapedNamePattern = escapeBashDoubleQuote(namePattern);

    // Construct the safe bash command pipeline
    const command = `find "${escapedDir}" -name "${escapedNamePattern}" -type f | xargs cat 2>/dev/null | grep "sudo" | wc -l`;

    try {
        const { stdout } = await execPromise(command);
        // Parse the output to integer, default to 0 if parsing fails
        const count = parseInt(stdout.trim(), 10);
        return isNaN(count) ? 0 : count;
    } catch (error) {
        throw new Error(`Failed to analyze sudo usage: ${error.message}`);
    }
}

module.exports = { analyzeSudoUsageInScripts };
